image.asymptote:
// 3-D interactive (WebGL) figure.
import graph3;
size(10cm);
currentprojection=orthographic(5,2.4,3);
real f(real x, real y){return 0.8+0.30*x+0.22*y;}
real L=4; int n=4; real d=L/n;
void column(real x0,real y0,real h){
  draw(shift((x0,y0,0))*scale(d,d,h)*unitcube, rgb(0.45,0.75,0.95)+opacity(0.55));
  triple a=(x0,y0,h),b=(x0+d,y0,h),c=(x0+d,y0+d,h),e=(x0,y0+d,h);
  draw(a--b--c--e--cycle, black+0.4pt);
  draw((x0,y0,0)--a,black+0.3pt); draw((x0+d,y0,0)--b,black+0.3pt);
  draw((x0+d,y0+d,0)--c,black+0.3pt); draw((x0,y0+d,0)--e,black+0.3pt);
}
for(int i=0;i<n;++i) for(int j=0;j<n;++j){
  real x0=i*d,y0=j*d,xm=x0+d/2,ym=y0+d/2,h=f(xm,ym);
  column(x0,y0,h); dot((xm,ym,h), red+3pt);
}
surface s=surface(new real(pair p){return f(p.x,p.y);},(0,0),(L,L),16,16);
draw(s, rgb(0.95,0.55,0.55)+opacity(0.30));
draw(O--(L+0.8,0,0),gray,Arrow3); draw(O--(0,L+0.8,0),gray,Arrow3); draw(O--(0,0,3.6),gray,Arrow3);
label("$x$",(L+0.8,0,0),S); label("$y$",(0,L+0.8,0),E); label("$z$",(0,0,3.6),N);

statement.p:
If the Riemann sums
\sum_i\sum_j f(x_{ij}^*,y_{ij}^*)\,\Delta A_{ij}
approach one number as the subrectangles get smaller, independent of the sample
points, then that number is called the double integral of f over
R, written
\boxed{\iint_R f(x,y)\,dA.}
